INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$GA4 & Matomo protocol compatibility$q$, $q$Ingests events from existing gtag.js or Matomo tracking snippets, minimizing migration effort for teams switching from either platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Native web tracker (beta)$q$, $q$An in-house tracker option for teams that want to collect data without depending on GA4 or Matomo tracking code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Warehouse-native storage$q$, $q$Writes a normalized, reporting-ready schema directly into ClickHouse, BigQuery, or CSV/Parquet files on S3, GCS, or local storage.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Server-side session calculation$q$, $q$Computes sessions on the backend instead of in the browser for more consistent, ad-blocker-resistant metrics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Flexible deployment$q$, $q$Runs as a free EU-hosted cloud service or fully self-hosted across Kubernetes, on-premises servers, or air-gapped networks.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Compliance-oriented architecture$q$, $q$Built with HIPAA, GDPR, FedRAMP, and SOX-style data residency and control requirements in mind.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$EU-hosted AI agent$q$, $q$Provides natural-language analysis over collected warehouse data to reduce manual SQL work.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Open-source codebase$q$, $q$MIT-licensed Go and TypeScript project on GitHub, open to community contributions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Full data ownership with no vendor lock-in into a third-party analytics dashboard.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Free to self-host indefinitely under a permissive MIT license.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Drop-in compatibility with existing GA4/Matomo tracking reduces migration effort.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Self-hosted and air-gapped options make it attractive for regulated industries.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Requires warehouse infrastructure knowledge (ClickHouse/BigQuery) to get full value.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Native web tracker is still in beta.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Limited third-party reviews and public track record given its early stage.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$No polished built-in BI or visualization layer; relies on external dashboards.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Is d8a free to use?$q$, $q$Yes. The self-hosted software is MIT-licensed and free, and d8a also offers a free EU-hosted cloud tier at app.d8a.tech.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Does d8a replace Google Analytics?$q$, $q$It can. d8a accepts GA4 Measurement Protocol events, so teams can redirect existing GA4 tracking into d8a's pipeline while keeping data outside Google's infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$What databases does d8a support?$q$, $q$ClickHouse and Google BigQuery as managed sinks, plus CSV/Parquet export to S3, Google Cloud Storage, or local storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Is d8a suitable for regulated industries?$q$, $q$The project markets self-hosted and air-gapped deployment options aimed at HIPAA, GDPR, FedRAMP, and SOX use cases, though organizations should independently verify compliance for their specific requirements.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Who maintains d8a?$q$, $q$d8a is developed as an open-source project on GitHub (d8a-tech/d8a), backed by a UK-registered company, D8A TECH UK LTD, with a community Discord for support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Does d8a include a built-in dashboard?$q$, $q$d8a focuses on ingestion and warehouse storage; visualization is typically handled by connecting BI tools such as Looker or Metabase to the resulting warehouse tables.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Privacy-first web analytics for regulated industries$q$, $q$Organizations needing GDPR/HIPAA-aligned data residency can self-host d8a on-premises or air-gapped, keeping clickstream data within their own infrastructure while still using familiar GA4/Matomo tracking.$q$, $q$Healthcare, government, and financial services teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Warehouse-native analytics for data teams$q$, $q$Teams already running BigQuery or ClickHouse can pipe web analytics directly into their warehouse via d8a instead of exporting from GA4, simplifying joins with other business data.$q$, $q$Data engineers and analysts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Free GA4 alternative for cost-conscious teams$q$, $q$Teams wanting to avoid GA4 data limits or Google's data handling can switch to d8a's free EU cloud tier with minimal tracking code changes.$q$, $q$Startups and indie developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["MIT license","Unlimited self-hosting","GA4 and Matomo protocol compatibility","Deploy on Kubernetes, on-premises, or air-gapped infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$Free Cloud$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["EU-hosted collector and warehouse pipeline","GDPR-oriented data residency","AI agent for ad hoc analysis","No credit card required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$d8a is an open-source, warehouse-native analytics platform that ingests events using GA4 and Matomo tracking protocols while writing the resulting data into a customer-controlled warehouse such as ClickHouse or BigQuery, rather than a vendor-owned dashboard.$q$, $q$The project is MIT-licensed and available as a free EU-hosted cloud tier or a fully self-hosted deployment, aimed at teams that want data ownership and compliance-friendly infrastructure alongside familiar GA4/Matomo-style tracking.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$d8a supports drop-in compatibility with existing GA4 and Matomo tracking snippets, server-side session computation, and export to ClickHouse, BigQuery, or CSV/Parquet on S3, GCS, or local storage, all under a documented reporting-ready schema.$q$, $q$Deployment options range from Kubernetes and on-premises installs to air-gapped networks, supporting compliance-sensitive sectors such as healthcare, government, and financial services, alongside an EU-hosted AI agent for natural-language analysis over the warehouse data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$d8a has no tiered subscription pricing. The self-hosted, MIT-licensed software is free to run on any infrastructure, and the EU-hosted cloud version at app.d8a.tech is offered free of charge with no credit card required.$q$, $q$No public enterprise or paid support tier is listed on the marketing site; teams needing dedicated support or contractual SLAs would need to contact the d8a team directly.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5186176-1b9e-4d69-9272-f95fc9700a4c', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Instant API generation$q$, $q$Layers a Node.js REST and GraphQL API on top of any SQL database without requiring data migration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Broad database support$q$, $q$Works with PostgreSQL, MySQL, SQLite, OracleDB, CockroachDB, MariaDB, and Microsoft SQL Server.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$No-code admin app$q$, $q$Gives non-technical team members a visual interface to browse records, manage files, and run queries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$JavaScript SDK and CLI$q$, $q$Provides developer tooling for programmatic access and scripted automation of the data platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Configurable permissions$q$, $q$Role-based access control lets teams govern who can read, write, or administer specific data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Webhooks and flow automation$q$, $q$Automates tasks and integrations triggered by data changes or scheduled events.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Self-hosted only$q$, $q$Deployable via Docker, bare metal, or any cloud provider, keeping data fully under the operator's control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$GPLv3 open-source license$q$, $q$Preserves the Directus 9 codebase and feature set as a permanently free, community-maintained fork.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Fully free and open source with no seat limits or feature gates.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Works with an existing SQL database with no forced migration.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Serves developers, analysts, and non-technical users from one unified API.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Backed by a company (La Webcapsule) with an established focus on compliance and self-hosting.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Self-hosted only, so there is no official managed cloud version of d9 itself.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Not affiliated with or supported by the official Directus core team.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Smaller community and documentation footprint than mainstream headless-CMS alternatives.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Requires infrastructure and database administration expertise to deploy and maintain.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$What is d9?$q$, $q$d9 is an open-source, GPLv3-licensed fork of Directus 9, maintained by La Webcapsule, that generates instant REST/GraphQL APIs and a no-code admin app over any SQL database.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Is d9 affiliated with Directus?$q$, $q$No. d9 is an independent, community-maintained fork and is explicitly not affiliated with the official Directus core team or company.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Is d9 free?$q$, $q$Yes, d9 is entirely free and open source under the GPLv3 license, with no paid tiers for the core software.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Can d9 be used with a cloud-hosted database?$q$, $q$Yes, d9 works with any SQL database it supports, whether self-hosted or run on a managed cloud database service, since it introspects the schema rather than requiring migration.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Which databases does d9 support?$q$, $q$PostgreSQL, MySQL, SQLite, OracleDB, CockroachDB, MariaDB, and Microsoft SQL Server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Who maintains d9?$q$, $q$d9 is maintained by La Webcapsule, a Paris-based engineering company (SAS, registered January 2022) that also builds compliance-focused engineering platforms and the open-source OrbiTS orchestration tool.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Instant backend API for an existing database$q$, $q$Teams with a production SQL database can deploy d9 to instantly expose REST and GraphQL endpoints without migrating data or rewriting the schema.$q$, $q$Backend developers and platform teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Staying on the open-source Directus 9 workflow$q$, $q$Organizations that prefer the Directus 9 feature set but do not want to adopt Directus's newer, more commercial licensing can migrate to d9 and keep receiving open-source updates.$q$, $q$Teams already using Directus 9$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$No-code data management for business teams$q$, $q$d9's admin app gives non-developers a way to browse, edit, and query data safely, governed by role-based permissions configured by IT.$q$, $q$Non-technical business users and analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPLv3 license","Self-hosted deployment via Docker or bare metal","Full API, SDK, CLI, and no-code app","No seat or feature limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$d9 is an open-source, GPLv3-licensed fork of Directus 9, maintained independently by the French company La Webcapsule after Directus moved later versions to a more commercial licensing model.$q$, $q$It instantly generates REST and GraphQL APIs, a JavaScript SDK, a CLI, and a no-code admin app on top of any existing SQL database, without requiring a data migration.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$d9 supports PostgreSQL, MySQL, SQLite, OracleDB, CockroachDB, MariaDB, and MS-SQL, introspecting each database's schema to build an abstraction layer that keeps the underlying data unaltered.$q$, $q$It provides CRUD operations, configurable user permissions, complex querying, and webhook/flow-based automation, serving developers, analysts, and non-technical business users from the same underlying API.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$d9 is free and open source under the GPLv3 license, with no paid tiers or feature gates for the core software; it is self-hosted only.$q$, $q$La Webcapsule separately sells custom, contact-sales engineering-platform and ISO 27001-compliant hosting services that can incorporate d9 for organizations wanting a managed, compliance-oriented deployment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b2320603-ad1f-48d1-a744-9445e8269225', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Software-defined assets$q$, $q$Declares data assets and their dependencies rather than raw tasks, giving automatic lineage and dependency graphs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Python-native pipeline authoring$q$, $q$Pipelines, schedules, and sensors are defined in Python with strong local testability.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Modern data stack integrations$q$, $q$Native integrations with dbt, Spark, Snowflake, BigQuery, Databricks, and major cloud object stores.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$AI and agent pipeline support$q$, $q$Increasingly used to orchestrate RAG pipelines, LLM workflows, and agent-based data tasks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Hybrid or serverless execution$q$, $q$Dagster+ can run customer code in the customer's own cloud (hybrid) or fully managed (serverless).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Built-in data catalog$q$, $q$Dagster+ provides catalog search across pipelines, assets, and metadata for platform-wide visibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Cost and usage tracking$q$, $q$Dagster+ tracks credit consumption and compute cost per asset, pipeline, or team.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$RBAC, audit logging, and SLAs$q$, $q$Enterprise-grade governance features available on paid Dagster+ plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Asset-based model gives built-in lineage and observability other orchestrators require add-ons for.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Strong local development and testing experience for Python-based pipelines.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Free, fully-featured open-source core with no artificial feature gating.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Post-acquisition, Prefect has committed to continued investment and unchanged pricing.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$The asset-centric abstraction has a steeper learning curve than simpler task-based schedulers.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Dagster+ credit-based pricing can be harder to forecast than flat per-seat pricing at scale.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Enterprise pricing is not publicly listed and requires a sales conversation.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Recent acquisition by Prefect introduces some uncertainty about long-term product direction, despite stated commitments.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Is Dagster free?$q$, $q$Yes, the open-source core of Dagster is free and Apache 2.0 licensed and can be self-hosted indefinitely. Dagster+ is a paid managed offering on top of it.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$What is Dagster+?$q$, $q$Dagster+ (formerly Dagster Cloud) is Dagster Labs' managed control plane, adding a hosted UI, catalog search, cost tracking, RBAC, audit logging, and SLAs, priced from $120/month for the Solo plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Who created Dagster?$q$, $q$Dagster was created by Nick Schrock, a former co-creator of GraphQL, who founded the company (originally Elementl, later renamed Dagster Labs) in 2018.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Did Dagster get acquired?$q$, $q$Yes. Prefect announced on July 13, 2026 that it was acquiring Dagster Labs, with both open-source Dagster and Dagster+ continuing to be maintained and priced as before under Prefect.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$How is Dagster different from Airflow?$q$, $q$Dagster centers on software-defined assets with built-in lineage and testability, while Airflow is a more task-centric scheduler; Dagster was explicitly designed as a next-generation alternative to Airflow.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Can Dagster orchestrate AI/LLM workflows?$q$, $q$Yes, Dagster is increasingly used to orchestrate RAG pipelines, LLM calls, and agentic workflows alongside traditional data engineering pipelines.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Modern ETL/ELT orchestration$q$, $q$Teams use Dagster to orchestrate ingestion, transformation (often via dbt), and loading into warehouses like Snowflake or BigQuery with built-in lineage.$q$, $q$Data engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$ML and AI pipeline orchestration$q$, $q$Dagster orchestrates feature engineering, model training, and increasingly RAG or agentic LLM pipelines as declarative asset graphs.$q$, $q$ML/AI engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Data platform observability and lineage$q$, $q$Organizations use Dagster's asset catalog and lineage graph to understand data freshness and dependencies across many pipelines from one place.$q$, $q$Data platform and analytics engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Apache 2.0 license","Full DAG engine, scheduler, and sensors","Local web UI","Self-hosted, unlimited use"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Dagster+ Solo$q$, $q$$120/month$q$, $q$monthly (pay-as-you-go, 7,500 credits included)$q$, NULL, $q$["1 user","1 code location","1 deployment","30-day free trial"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Dagster+ Starter$q$, $q$$1,200/month$q$, $q$monthly (pay-as-you-go, 30,000 credits included)$q$, NULL, $q$["Up to 3 users","5 code locations","1 deployment","Catalog search"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$Dagster+ Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Unlimited code locations and deployments","Cost tracking","Dedicated support channel","Uptime SLAs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dagster is an open-source data orchestration platform, created by Nick Schrock and originally built by the company Elementl (later renamed Dagster Labs), founded in 2018 in San Francisco.$q$, $q$It organizes pipelines around software-defined assets rather than plain tasks, giving teams built-in lineage and observability, and in July 2026 Dagster Labs was acquired by orchestration rival Prefect, which committed to keeping both products and their pricing unchanged.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dagster pipelines are authored in Python and integrate with dbt, Spark, Snowflake, BigQuery, Databricks, and common cloud storage, with growing support for orchestrating AI/LLM and agentic workflows alongside traditional ETL.$q$, $q$The open-source core (Apache 2.0) includes the DAG engine, scheduler, sensors, and a local web UI, while the managed Dagster+ product adds a hosted control plane, catalog search, cost tracking, RBAC, audit logging, and uptime SLAs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Self-hosting the open-source core is free. Dagster+ Solo costs $120/month with 7,500 credits, and Starter costs $1,200/month with 30,000 credits, both under the pricing structure effective May 1, 2026.$q$, $q$An Enterprise tier is available on a custom quote basis with unlimited code locations and deployments, and a 30-day free trial with unlimited users is offered for teams evaluating Dagster+.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
