INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aef224a1-fe25-4992-8146-62c270b751d5', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Single-binary, zero-dependency architecture$q$, $q$Runs the scheduler, web UI, and execution engine from one Go binary with no required external database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Declarative YAML DAGs$q$, $q$Workflows are defined in simple YAML, wrapping existing shell scripts, SQL, and tools without rewriting them.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Multiple executors$q$, $q$Native support for shell commands, Docker containers, Kubernetes jobs, SSH, HTTP requests, and SQL queries.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Built-in web UI$q$, $q$Visualizes DAG dependencies, execution status, logs, and allows manual workflow triggering.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$MCP server for AI agents$q$, $q$Lets AI coding agents like Claude Code, Codex, and Gemini CLI author and run Dagu workflows directly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Distributed execution$q$, $q$Coordinator/worker architecture with label-based routing scales Dagu across multiple machines.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Operational controls$q$, $q$Parameters, human approval steps, retries, cron scheduling, and artifact passing between steps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Enterprise add-ons$q$, $q$Paid licenses add SSO, RBAC, audit logging, and dedicated support on top of the free core.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Extremely lightweight; installs and runs as one binary with no database to manage.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Free, GPLv3-licensed community edition with unlimited self-hosted servers and workers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Simple YAML workflow definitions with a built-in web UI for visibility.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Built-in MCP server makes it a natural fit for AI-agent-driven automation.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Smaller ecosystem and community than established orchestrators like Airflow or Prefect.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Enterprise features (SSO, RBAC, audit logging) require a paid license.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Public information on the company's founding date, size, and funding is limited.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Best suited to small-to-mid scale workloads; very large-scale orchestration may still favor heavier platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Is Dagu free?$q$, $q$Yes, Dagu's community edition is GPLv3-licensed and free forever, with unlimited self-hosted servers and workers and core scheduling/execution features included.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Does Dagu require a database?$q$, $q$No. Dagu stores execution state in local files by default and runs as a single binary with no required external database or message broker.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Can Dagu run Docker or Kubernetes jobs?$q$, $q$Yes, Dagu has native executors for Docker containers, Kubernetes jobs, SSH commands, HTTP requests, and SQL queries in addition to shell commands.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$What are Dagu's paid plans for?$q$, $q$Paid self-hosted licenses (Minimum at $50/month and Pro at $150/month) add enterprise features like SSO, RBAC, and audit logging on top of the free core engine.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Can AI agents use Dagu?$q$, $q$Yes, Dagu includes a built-in Model Context Protocol (MCP) server that lets AI coding agents such as Claude Code and Gemini CLI author and run workflows directly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$How is Dagu different from Airflow?$q$, $q$Dagu is designed to avoid Airflow's operational complexity, running as a single dependency-free binary instead of requiring a database, broker, and multiple long-running services.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Lightweight ETL and data pipeline scheduling$q$, $q$Teams that find Airflow too heavy use Dagu to schedule and monitor ETL jobs with a simple YAML DAG and built-in web UI.$q$, $q$Small data teams and solo developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Legacy script and infrastructure automation$q$, $q$Dagu wraps existing shell scripts, SSH commands, and infrastructure tasks into observable, retryable, schedulable workflows without rewriting them.$q$, $q$DevOps and SRE-adjacent engineers at small companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$AI-agent-driven task orchestration$q$, $q$Dagu's MCP server lets AI coding agents define and execute multi-step workflows directly, useful for agentic automation pipelines.$q$, $q$Developers building AI agent workflows$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Community (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPLv3 license, free forever","Unlimited self-hosted servers and workers","Web UI, scheduling, and core executors","Up to 2 API keys"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Minimum$q$, $q$$50/month$q$, $q$monthly$q$, NULL, $q$["Up to 3 server licenses","SSO and RBAC","Audit logging","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Pro$q$, $q$$150/month$q$, $q$monthly$q$, NULL, $q$["Up to 15 server licenses","SSO and RBAC","Audit logging","Email support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Architecture consulting","Custom implementation","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dagu is a lightweight, self-contained workflow orchestration engine, written in Go, that runs as a single binary with no external database requirement, positioned explicitly as an alternative to Apache Airflow and cron for teams that don't want to run an SRE-heavy orchestration platform.$q$, $q$Workflows are defined as YAML-based DAGs supporting shell, Docker, Kubernetes, SSH, HTTP, and SQL steps, with a built-in web UI, scheduling, retries, and — increasingly — a Model Context Protocol server so AI coding agents can author and run workflows directly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dagu supports three deployment modes — standalone, headless, and distributed with a coordinator and labeled workers — letting it scale from a single laptop to a small fleet without switching products.$q$, $q$It is used in production for ETL, legacy script orchestration, media conversion, infrastructure automation, containerized batch jobs, and AI-agent-driven task execution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The community edition is GPLv3-licensed and free forever, supporting unlimited self-hosted servers and workers with core scheduling and execution features.$q$, $q$Paid self-hosted licenses add enterprise controls: Minimum is $50/month (up to 3 servers), Pro is $150/month (up to 15 servers), and Enterprise is custom-priced; a managed GKE-hosted cloud option is also available.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('65a38524-812b-4ba7-9eff-27f973a0e40d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Full daily star history$q$, $q$Reconstructs accurate daily star counts even for repositories with more than 40,000 stars, beyond GitHub API's default limit.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Hourly spike analysis$q$, $q$A 'Stars by Hour' chart pinpoints exactly when growth spikes happened, layered against the cumulative star line.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Repository comparison$q$, $q$Compares two repositories' growth trajectories side by side.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Broader activity tracking$q$, $q$Tracks commits, pull requests, issues, and contributor counts alongside stars for a fuller project health picture.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Spike source attribution$q$, $q$Surfaces mentions from Hacker News, Reddit, YouTube, and GitHub tied to specific growth spikes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Trend forecasting$q$, $q$Applies Facebook's Prophet library to visualize aggregated trends over raw daily data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Data export$q$, $q$Exports underlying star and activity data as CSV or JSON for further analysis.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Self-hostable via Docker$q$, $q$Can be run locally or on private infrastructure instead of relying on the hosted instance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Completely free and open source with no account or payment required.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Overcomes GitHub's 40,000-star API limitation to show true historical growth curves.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Provides deeper insight than star counts alone via activity metrics and spike source attribution.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Can be self-hosted via Docker for privacy or to avoid shared rate limits.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$First-time data fetches for very large repositories can take several minutes.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Maintained by a single developer, so support and update cadence depend on one person's availability.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Limited to public GitHub repository data unless self-hosted with appropriate access tokens.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$No official roadmap, SLA, or commercial support since it is a free side project rather than a company.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Is Daily Stars Explorer free?$q$, $q$Yes, it is completely free to use at emanuelef.github.io/daily-stars-explorer, and the MIT-licensed source code can also be self-hosted for free.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$How does it show star history beyond GitHub's 40,000-star limit?$q$, $q$It fetches star history from both the start and end of a repository's timeline simultaneously, reconstructing the true daily curve rather than the interpolated line most star-history tools show for very popular repositories.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Who created Daily Stars Explorer?$q$, $q$It was created and is maintained by developer Emanuele Fumagalli (GitHub handle emanuelef) as an open-source project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Can I compare two repositories?$q$, $q$Yes, the tool includes a comparison feature to view two repositories' star growth trajectories side by side.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Does it track anything besides stars?$q$, $q$Yes, it also tracks commits, pull requests, issues, contributors, and surfaces external mentions from Hacker News, Reddit, and YouTube tied to growth spikes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Can I self-host Daily Stars Explorer?$q$, $q$Yes, it is packaged for Docker deployment so users can run their own instance instead of using the public GitHub Pages site.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Tracking your own open-source project's growth$q$, $q$Maintainers use Daily Stars Explorer to see exactly when their star growth spiked and correlate it with launches, Hacker News posts, or social media mentions.$q$, $q$Open-source maintainers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Comparing competing open-source libraries$q$, $q$Developers choosing between two similar open-source libraries use the comparison feature to see relative growth and momentum over time.$q$, $q$Developers evaluating tools$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Open-source ecosystem research$q$, $q$Researchers writing about open-source trends or evaluating projects for investment due diligence use the tool's activity metrics and true historical star curves.$q$, $q$Analysts, investors, and content creators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full hosted access at emanuelef.github.io/daily-stars-explorer","Unlimited repository lookups (subject to GitHub API rate limits)","CSV/JSON export","Self-hostable via Docker"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Daily Stars Explorer is a free, open-source tool built by developer Emanuele Fumagalli (GitHub handle emanuelef) that reconstructs the complete daily, and recently hourly, star history of any public GitHub repository, including projects with more than 40,000 stars where GitHub's own API only exposes recent stargazers.$q$, $q$It is hosted at emanuelef.github.io/daily-stars-explorer, released under the MIT license, and can also be self-hosted via Docker.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The tool fetches star history from both ends of a repository's timeline simultaneously to reconstruct accurate daily data even for very large repositories, and adds an hourly 'Stars by Hour' view to pinpoint exactly when growth spikes occurred.$q$, $q$Beyond stars, it tracks commits, forks, issues, pull requests, and contributors, supports side-by-side repository comparisons, surfaces Hacker News/Reddit/YouTube mentions tied to spikes, and offers CSV/JSON export and Prophet-based trend forecasting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Daily Stars Explorer is entirely free to use at its hosted GitHub Pages URL, with no subscription tiers or paid features.$q$, $q$The MIT-licensed source code can also be self-hosted for free via Docker for users who want their own instance or to avoid shared API rate limits.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d0f250c-fcb6-42a1-ba65-14a33ddeb307', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Text-to-image generation$q$, $q$Generates original images from natural-language text prompts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$ChatGPT conversational editing$q$, $q$Lets users refine generated images through natural-language follow-up prompts inside ChatGPT.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$In-image text rendering$q$, $q$Renders legible text within generated images more reliably than many earlier-generation competitors.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$API access for developers$q$, $q$Offered programmatic image generation for third-party applications, priced per image (being phased out for DALL-E 3).$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Multiple resolution/quality tiers$q$, $q$Supported standard and HD quality outputs at varying resolutions and price points.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Prompt adherence to complex scenes$q$, $q$Handled multi-object, multi-attribute prompts with comparatively strong accuracy for its era.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Integration with ChatGPT's free and paid tiers$q$, $q$Available to ChatGPT Plus/Enterprise subscribers, with limited daily generations for free-tier users.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Succeeded by GPT Image models$q$, $q$OpenAI's GPT Image 1 and GPT Image 1.5 now serve as the actively maintained successors as DALL-E 3 is retired.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Deep, conversational integration with ChatGPT made iterative image editing simple for non-technical users.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Strong historical reputation for prompt accuracy and legible in-image text versus older competitors.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Accessible to a huge existing user base through ChatGPT's free and paid tiers.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$OpenAI provides a clear, actively supported successor (GPT Image) for continuity.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$DALL-E 3 is being retired from the API on May 12, 2026, requiring developers to migrate.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$No longer OpenAI's default or most capable image model as of 2026; GPT Image models have superseded it.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Free-tier ChatGPT image generation is limited to a small number of images per day.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Newer competitors like Flux and Midjourney are frequently cited as matching or beating DALL-E 3 on quality and price.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Is DALL-E 3 still available in 2026?$q$, $q$It is being phased out. OpenAI is removing DALL-E 3 from its API on May 12, 2026, and ChatGPT's default image generation already shifted to the newer GPT Image model line in December 2025.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$What replaced DALL-E 3?$q$, $q$OpenAI's GPT Image 1 and GPT Image 1.5 models are the actively maintained successors, offering improved quality and, in some cases, lower per-image API pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$How much does DALL-E 3 cost via the API?$q$, $q$Historically, standard 1024x1024 images cost about $0.04 each, with HD or higher-resolution outputs priced between roughly $0.08 and $0.12 per image, though this access is being retired.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Can I still generate images for free with DALL-E-branded tools?$q$, $q$ChatGPT's free tier includes a small daily allowance of AI-generated images (typically a few per day), though these are now generated by GPT Image models rather than DALL-E 3 specifically.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Who created DALL-E?$q$, $q$DALL-E was created by OpenAI, the AI research company founded in San Francisco in December 2015, with the original DALL-E announced in January 2021.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$What are DALL-E's main competitors?$q$, $q$Midjourney, Stability AI's Stable Diffusion, Google's Imagen/Gemini image generation, Adobe Firefly, and the open-weight Flux model family are its most commonly cited competitors.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Conversational image generation for everyday users$q$, $q$Casual users generate and iteratively refine images directly inside ChatGPT conversations without needing a separate design tool.$q$, $q$ChatGPT Plus and free-tier consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Marketing and content visual assets$q$, $q$Teams use DALL-E-family models to quickly produce blog headers, social graphics, and campaign visuals from text prompts.$q$, $q$Marketers and content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$Developer-integrated image generation (legacy)$q$, $q$Applications that previously called the DALL-E 3 API for programmatic image generation need to migrate to GPT Image 1/1.5 ahead of the May 2026 API retirement.$q$, $q$Developers building on the OpenAI API$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$ChatGPT Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Limited daily AI image generations (currently via GPT Image models)","Access within ChatGPT's chat interface"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$ChatGPT Plus$q$, $q$$20/month$q$, $q$monthly$q$, NULL, $q$["Higher image generation limits","Conversational image editing","Priority access to newest models"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$API (legacy DALL-E 3, retiring May 2026)$q$, $q$From $0.04/image$q$, $q$pay-per-image$q$, NULL, $q$["Standard 1024x1024 images from $0.04","HD/higher-resolution images $0.08-$0.12","Being replaced by GPT Image 1/1.5 API pricing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$DALL-E is OpenAI's family of text-to-image AI models, starting with the original DALL-E (announced January 2021), DALL-E 2 (launched April 2022), and DALL-E 3 (released in ChatGPT in October 2023).$q$, $q$As of 2026, DALL-E 3 is being formally retired: OpenAI is removing it from the API on May 12, 2026, and ChatGPT's default image generation has already shifted to the newer GPT Image model line.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$DALL-E 3's main strengths were tight conversational integration with ChatGPT, strong adherence to complex multi-object prompts, and comparatively reliable rendering of legible text inside generated images.$q$, $q$It was accessible through ChatGPT Plus/Enterprise subscriptions, a limited ChatGPT free tier, and a pay-per-image API, though all API access is being phased out in favor of GPT Image 1 and GPT Image 1.5.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$DALL-E 3 image generation was included in ChatGPT Plus ($20/month) and Enterprise plans, with a small daily free-tier allowance, while API pricing ran from about $0.04/image (standard) to $0.08-$0.12/image (HD/higher resolution).$q$, $q$With DALL-E 3's API retirement on May 12, 2026, OpenAI's GPT Image 1.5 (from about $0.03/image) is now the primary supported and forward-looking pricing reference for OpenAI image generation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c4134253-62ea-44f0-8d58-12d26946aac4', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Zero-knowledge encrypted vault$q$, $q$Stores passwords, passkeys, and payment details with end-to-end encryption Dashlane itself cannot access.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Cross-platform apps and extensions$q$, $q$Native apps for Windows, macOS, iOS, and Android plus browser extensions for major browsers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Built-in VPN$q$, $q$Included with Premium to protect traffic on public Wi-Fi networks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$AI-powered scam protection$q$, $q$Warns users in real time before autofilling credentials on suspected phishing or scam sites.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Dark web monitoring$q$, $q$Alerts users when their credentials appear in known data breaches.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Passkey Linked Domains$q$, $q$Improves passkey matching and autofill across related company domains, launched February 2026.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Secure sharing and Friends & Family$q$, $q$Lets users securely share credentials with trusted contacts or extend protection to family members.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Business SSO/SCIM and credential governance$q$, $q$Omnix and Enterprise plans integrate with SSO/SCIM and manage workforce password policy centrally.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$All-in-one bundle of password manager, VPN, dark web monitoring, and AI scam protection.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Strong cross-platform coverage across Windows, macOS, iOS, Android, and major browsers.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Actively investing in passwordless/passkey features as authentication standards evolve.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Robust business tier (Omnix) with SSO/SCIM and credential-breach prevention outside SSO.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$No longer offers a free plan as of September 2025, unlike some direct competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Full public pricing for several tiers is not transparently listed and requires visiting the pricing pages or contacting sales.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$VPN is only bundled with the higher Premium tier, not lower-cost options.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Business/Enterprise pricing is largely custom and not self-serve for larger organizations.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Does Dashlane have a free plan?$q$, $q$No. Dashlane retired its Free plan on September 16, 2025; it now operates as a paid-only subscription with a 30-day money-back guarantee for new subscribers instead of an ongoing free tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$What does Dashlane's Premium plan include?$q$, $q$Unlimited password and passkey storage, unlimited devices, a built-in VPN, AI-powered scam protection, secure sharing, dark web monitoring, 1GB of encrypted document storage, and two-factor authentication.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Who founded Dashlane?$q$, $q$Dashlane was founded in 2009 by Emmanuel Schalit, Bernard Liautaud, Alexis Fogel, and Jean Guillou, and is headquartered in New York City.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Does Dashlane offer business plans?$q$, $q$Yes, including a flat-rate Starter plan for up to 10 users, per-seat Business and Omnix tiers with SSO/SCIM integration, and a custom-priced Enterprise tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$What is Dashlane's AI scam protection?$q$, $q$It's a feature that analyzes sites and autofill context in real time to warn users before they enter credentials or payment details on a suspected phishing or scam page.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$What are Dashlane's main competitors?$q$, $q$1Password, Bitwarden, NordPass, and Keeper are among its most commonly compared competitors in the password manager category.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$All-in-one personal digital security$q$, $q$Individuals use Dashlane's Premium plan to store passwords and passkeys, browse securely with the built-in VPN, and get alerted to data breaches and scam sites.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Family password and identity protection$q$, $q$The Friends & Family plan lets up to 10 family members share centrally managed password protection under one subscription.$q$, $q$Families and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Enterprise credential governance$q$, $q$Businesses use Dashlane's Omnix or Enterprise tiers to enforce password policy, integrate with SSO/SCIM, and prevent credential breaches across domains outside their SSO perimeter.$q$, $q$IT and security teams at mid-size to large businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Premium (Personal)$q$, $q$From ~$4.99/month$q$, $q$billed annually$q$, NULL, $q$["Unlimited password/passkey storage","Unlimited devices","Built-in VPN","AI scam protection","Dark web monitoring","1GB encrypted document storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Friends & Family$q$, $q$~$8/month for up to 10 members$q$, $q$billed annually$q$, NULL, $q$["Up to 10 family members","Premium features for the plan manager","Unlimited password storage and devices per member","Secure sharing dashboard"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Business Starter$q$, $q$$30/month flat$q$, $q$monthly$q$, NULL, $q$["Up to 10 users","Core password management","Admin console"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Business$q$, $q$~$8/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Per-user password management","Team sharing and policies","Admin reporting"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Omnix$q$, $q$~$11/user/month$q$, $q$monthly or annual$q$, NULL, $q$["SSO/SCIM integration","Credential breach prevention outside SSO","Phishing risk detection"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$Enterprise$q$, $q$Custom$q$, $q$Contact sales$q$, NULL, $q$["Volume-based pricing","Dedicated account management","Tailored credential security package"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dashlane is a password management and digital identity security platform founded in 2009 by Emmanuel Schalit, Bernard Liautaud, Alexis Fogel, and Jean Guillou, headquartered in New York City, and backed by roughly $192 million in venture funding.$q$, $q$It stores passwords, passkeys, and payment details in a zero-knowledge encrypted vault synced across Windows, macOS, iOS, and Android apps and major browser extensions, serving more than 19 million users and 22,000+ businesses as of 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond core password autofill, Dashlane bundles a built-in VPN, dark web breach monitoring, secure password sharing, encrypted document storage, and AI-powered scam/phishing protection into its Premium subscription.$q$, $q$In February 2026 it launched Passkey Linked Domains to improve cross-domain passkey autofill, reflecting continued investment in passwordless authentication alongside traditional password management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dashlane retired its free plan on September 16, 2025 and now operates as a paid-only subscription product, though it offers a 30-day money-back guarantee for new subscribers.$q$, $q$Personal plans include Premium (individual) and Friends & Family (up to 10 members), while business plans include Starter (flat rate, up to 10 users), per-seat Business, per-seat Omnix, and a custom-priced Enterprise tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
