INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4504a9e9-0f49-455b-ad80-15afb8c4139d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Content Brief Builder$q$, $q$Compiles competitor research and target-keyword data into an interactive, shareable content brief for writers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Real-time content scoring$q$, $q$Scores drafts against top-ranking competitor content as writers work, before publishing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Content Monitoring$q$, $q$Tracks live content's search rankings and organic performance, flagging pages that need refreshing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Weekly keyword reports$q$, $q$Sends automated reports on ranking movement for tracked keywords and pages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$AI Writer$q$, $q$Generates draft content within a plan's monthly AI-word allowance to speed up first drafts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Competitor analysis$q$, $q$Analyzes top-ranking pages for a keyword to surface topics, headers, and terms to include.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Bulk report creation$q$, $q$Available on higher plans for agencies and teams managing many content pieces at once.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$API access and SSO$q$, $q$Available on the Business and Enterprise plans for integration and centralized authentication.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Combines content briefs, optimization scoring, and post-publish monitoring in one platform.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Straightforward two-tier-plus-enterprise pricing structure that's easy to compare against competitors.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Free trial with a full content report and no credit card required lowers the barrier to evaluation.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Content Monitoring helps teams prioritize which existing articles to update, not just new content.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Smaller company with limited public information on team size, funding, or long-term roadmap.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Faces well-established, larger competitors like Surfer SEO with bigger integration ecosystems.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Entry-level Startup plan's report and seat limits may be restrictive for larger content teams.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Full pricing for the Enterprise tier is not transparently published and requires contacting sales.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$How much does Dashword cost?$q$, $q$The Startup plan starts at $99/month, the Business plan starts around $349/month, and an Enterprise tier starts around $699/month, with roughly a 20% discount for annual billing.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Does Dashword offer a free trial?$q$, $q$Yes, Dashword offers a free trial including a full content report with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$What does Dashword's Content Monitoring do?$q$, $q$It tracks published content's search rankings and organic performance over time, flagging underperforming or decaying pages and sending weekly keyword reports.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Does Dashword include AI writing?$q$, $q$Yes, its AI Writer feature can generate draft content within the monthly AI-word allowance of a given plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Where is Dashword based?$q$, $q$Dashword was founded in 2019 and is headquartered in Tallinn, Estonia.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$What are Dashword's main competitors?$q$, $q$Surfer SEO, Clearscope, MarketMuse, and Frase are among the most commonly compared AI-driven SEO content optimization competitors.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Data-backed content brief creation$q$, $q$Teams use Dashword to build competitor-informed content briefs and hand them off to writers so drafts start with clear SEO guidance.$q$, $q$Content strategists and editors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Real-time on-page SEO optimization$q$, $q$Writers use Dashword's live scoring to improve topic coverage and keyword usage in a draft before it is published.$q$, $q$SEO writers and freelance content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Ongoing content refresh prioritization$q$, $q$Teams managing large content libraries use Content Monitoring to identify which existing articles are losing rankings and need updates.$q$, $q$SEO managers and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Startup$q$, $q$$99/month$q$, $q$monthly (20% off annually)$q$, NULL, $q$["~20-30 monthly content reports","5 user seats","Content Briefs","Content Optimization","AI Writer"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Business$q$, $q$From $349/month$q$, $q$monthly (20% off annually)$q$, NULL, $q$["~100 monthly content reports","10 user seats","Bulk report creation","API access","Single Sign-On (SSO)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$Enterprise$q$, $q$From ~$699/month$q$, $q$monthly (20% off annually)$q$, NULL, $q$["100+ monthly content reports","~20 user seats","Content Monitoring","API access"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Dashword is an AI-powered SEO content optimization platform, founded in 2019 and headquartered in Tallinn, Estonia, built around content briefs, real-time optimization scoring, and post-publish performance monitoring.$q$, $q$It targets content marketers, SEO teams, and agencies that want a single workflow spanning research, writing guidance, and ongoing content maintenance rather than separate point tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Dashword's Content Brief Builder compiles competitor research and recommended topics into shareable briefs, while its Content Optimization tool scores drafts against what is currently ranking for a target keyword in real time.$q$, $q$Content Monitoring tracks rankings and organic performance after publication, flagging underperforming pages via weekly keyword reports, and an AI Writer feature helps generate draft content within plan word limits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Dashword's Startup plan costs $99/month with around 20-30 content reports and 5 user seats, while the Business plan starts around $349/month with roughly 100 reports, 10 seats, bulk report creation, API access, and SSO.$q$, $q$An Enterprise tier starts around $699/month for larger teams, annual billing carries roughly a 20% discount, and a free trial with a full content report is available with no credit card required.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6d0ecf12-94ea-40bf-8961-2c520ff5df26', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
